+// -----------------------------------------------------------------------------
+// FilePicker Field
+// -----------------------------------------------------------------------------
+
+/// A file picker field for selecting files and directories.
+///
+/// The FilePicker field allows users to browse the filesystem and select files
+/// or directories. It can be configured to filter by file type, show/hide hidden
+/// files, and control whether files and/or directories can be selected.
+///
+/// # Example
+///
+/// ```rust,ignore
+/// use huh::FilePicker;
+///
+/// let picker = FilePicker::new()
+///     .key("config_file")
+///     .title("Select Configuration File")
+///     .description("Choose a .toml or .json file")
+///     .allowed_types(vec![".toml".to_string(), ".json".to_string()])
+///     .current_directory(".");
+/// ```
+pub struct FilePicker {
+    id: usize,
+    key: String,
+    selected_path: Option<String>,
+    title: String,
+    description: String,
+    current_directory: String,
+    allowed_types: Vec<String>,
+    show_hidden: bool,
+    show_size: bool,
+    show_permissions: bool,
+    file_allowed: bool,
+    dir_allowed: bool,
+    picking: bool,
+    focused: bool,
+    error: Option<String>,
+    validate: Option<fn(&str) -> Option<String>>,
+    width: usize,
+    height: usize,
+    theme: Option<Theme>,
+    keymap: FilePickerKeyMap,
+    _position: FieldPosition,
+    // Simple file list for display
+    files: Vec<FileEntry>,
+    selected_index: usize,
+    offset: usize,
+}
+
+/// A file entry in the picker.
+#[derive(Debug, Clone)]
+struct FileEntry {
+    name: String,
+    path: String,
+    is_dir: bool,
+    size: u64,
+    #[allow(dead_code)]
+    mode: String,
+}
+
+impl Default for FilePicker {
+    fn default() -> Self {
+        Self::new()
+    }
+}
+
+impl FilePicker {
+    /// Creates a new file picker field.
+    pub fn new() -> Self {
+        Self {
+            id: next_id(),
+            key: String::new(),
+            selected_path: None,
+            title: String::new(),
+            description: String::new(),
+            current_directory: ".".to_string(),
+            allowed_types: Vec::new(),
+            show_hidden: false,
+            show_size: false,
+            show_permissions: false,
+            file_allowed: true,
+            dir_allowed: false,
+            picking: false,
+            focused: false,
+            error: None,
+            validate: None,
+            width: 80,
+            height: 10,
+            theme: None,
+            keymap: FilePickerKeyMap::default(),
+            _position: FieldPosition::default(),
+            files: Vec::new(),
+            selected_index: 0,
+            offset: 0,
+        }
+    }
+
+    /// Sets the field key.
+    pub fn key(mut self, key: impl Into<String>) -> Self {
+        self.key = key.into();
+        self
+    }
+
+    /// Sets the title.
+    pub fn title(mut self, title: impl Into<String>) -> Self {
+        self.title = title.into();
+        self
+    }
+
